</template>

<script>
import { mapState, mapActions } from 'vuex'
import Swiper, { Navigation, Pagination } from 'swiper'
import 'swiper/swiper-bundle.css'

export default {
  name: 'MainComp',
  data () {
    return {
      loading: true,
      itemsPerPage: 6,
      postcards: []
      // currentPage: 1,
    }
  },
  computed: {
    projects () { return this.$store.state.S20242030.projects },
    ...mapState('S20242030', [
      'urlParams',
      'img_siepi',
      'windowWidth',
      'images',
      'video',
      'dialog_data',
      'Carousel'
    ]),
    formattedContent () {
      return this.dialog_data.items.content.replace(/\n\n/g, '<br> <br>')
    },
    paginatedImages () {
      const start = (this.dialog_data.currentPage - 1) * this.itemsPerPage
      return this.dialog_data.items.galery_img.slice(start, start + this.itemsPerPage)
    },
    pageCount () {
      return Math.ceil(this.dialog_data.items.galery_img.length / this.itemsPerPage)
    }
  },
  methods: {
    ...mapActions('S20242030', [
      'setDialog',
      'expandFile',
      'openImagesCarousel',
      'loadData'
    ]),
    srcset (src) {
      return `${src}?w=200 200w, ${src}?w=400 400w`
    },
    truncateText (text, maxLength) {
      if (text.length > maxLength) {
        return text.substring(0, maxLength) + '...'
      }
      return text
    },
    onImageLoad () {
      this.loading = false
    },
    onImageError () {
      this.loading = false
    },
    updateUrl (page) {
      // this.currentPage = page
      // const url = new URL(window.location)
      // url.searchParams.set('page', page)
      // window.history.pushState({}, '', url)
    },

    async openImages (element) {
      const { index, paginatedImages } = element
      const images = await paginatedImages.map(item => ({
        src: item.img
      }))
      this.openImagesCarousel({ index, paginatedImages: images })
    },
    async getProjects () {
      const data = await this.loadData('20242030/json/proyectos.json')
      const shuffled = await [...data].sort(() => 0.5 - Math.random())
      this.$store.state.S20242030.projects = shuffled.slice(0, data.length)
    },
    async getPostcards () {
      const post = await this.loadData('20242030/json/postcards.json')
      const shuffled = await [...post].sort(() => 0.5 - Math.random())
      this.postcards = shuffled.slice(0, 4)
    }
  },
  mounted () {
    // Swiper.use([Navigation, Pagination])
    const swiper = new Swiper(this.$refs.swiperEl, { // mySwiper this.$refs.swiperEl
      modules: [Navigation, Pagination],
      init: false,
      loop: true,
      spaceBetween: 20,
      grabCursor: true,

      // observer: true,
      // observeParents: true,

      // loopedSlides: 3,
      // loopFillGroupWithBlank: false,

      pagination: {
        el: '.swiper-pagination',
        clickable: true,
        dynamicBullets: true
      },
      navigation: {
        nextEl: '.swiper-button-next',
        prevEl: '.swiper-button-prev'
      },
      breakpoints: {
        0: { slidesPerView: 1 },
        600: { slidesPerView: 2 },
        968: { slidesPerView: 3 }
      }
    })

    this.swiper = swiper
  },
  async created () {
    document.title = 'Inicio | Sistema de Información y Estadística sobre los Pueblos y Comunidades Indígenas'
  }
}
</script>

